dataSource.saveQuery:
DECLARE
  v_start_date DATE;
  v_end_date DATE;
  v_start_str VARCHAR2(100) := TRIM(:p_start_date);
  v_end_str VARCHAR2(100) := TRIM(:p_end_date);
  v_treatment_id VARCHAR2(50) := :p_treatment_id;
  v_cnt NUMBER;
BEGIN
  -- Parse START_DATE
  IF v_start_str IS NOT NULL THEN
    IF REGEXP_LIKE(v_start_str, '^\d{4}[-/]\d{2}[-/]\d{2}') THEN
      v_start_date := TO_DATE(SUBSTR(v_start_str, 1, 10), CASE WHEN SUBSTR(v_start_str, 5, 1) = '/' THEN 'YYYY/MM/DD' ELSE 'YYYY-MM-DD' END);
    ELSIF REGEXP_LIKE(v_start_str, '^\d{2}[-/]\d{2}[-/]\d{4}') THEN
      v_start_date := TO_DATE(SUBSTR(v_start_str, 1, 10), CASE WHEN SUBSTR(v_start_str, 3, 1) = '/' THEN 'DD/MM/YYYY' ELSE 'DD-MM-YYYY' END);
    ELSE
      BEGIN
        v_start_date := TO_DATE(SUBSTR(v_start_str, 1, 10), 'YYYY-MM-DD');
      EXCEPTION WHEN OTHERS THEN
        BEGIN
          v_start_date := TO_DATE(SUBSTR(v_start_str, 1, 10), 'DD/MM/YYYY');
        EXCEPTION WHEN OTHERS THEN
          v_start_date := NULL;
        END;
      END;
    END IF;
  END IF;
  v_start_date := NVL(v_start_date, TRUNC(SYSDATE));

  -- Parse END_DATE
  IF v_end_str IS NOT NULL THEN
    IF REGEXP_LIKE(v_end_str, '^\d{4}[-/]\d{2}[-/]\d{2}') THEN
      v_end_date := TO_DATE(SUBSTR(v_end_str, 1, 10), CASE WHEN SUBSTR(v_end_str, 5, 1) = '/' THEN 'YYYY/MM/DD' ELSE 'YYYY-MM-DD' END);
    ELSIF REGEXP_LIKE(v_end_str, '^\d{2}[-/]\d{2}[-/]\d{4}') THEN
      v_end_date := TO_DATE(SUBSTR(v_end_str, 1, 10), CASE WHEN SUBSTR(v_end_str, 3, 1) = '/' THEN 'DD/MM/YYYY' ELSE 'DD-MM-YYYY' END);
    ELSE
      BEGIN
        v_end_date := TO_DATE(SUBSTR(v_end_str, 1, 10), 'YYYY-MM-DD');
      EXCEPTION WHEN OTHERS THEN
        BEGIN
          v_end_date := TO_DATE(SUBSTR(v_end_str, 1, 10), 'DD/MM/YYYY');
        EXCEPTION WHEN OTHERS THEN
          v_end_date := NULL;
        END;
      END;
    END IF;
  END IF;

  -- Validate unique TREATMENT_CODE (case-insensitive)
  IF v_treatment_id IS NULL OR v_treatment_id = '' THEN
    SELECT COUNT(*) INTO v_cnt FROM DEMO_TREATMENTS WHERE LOWER(TREATMENT_CODE) = LOWER(TRIM(:p_treatment_code));
    IF v_cnt > 0 THEN
      raise_application_error(-20001, 'Mã điều trị đã tồn tại trong hệ thống. Vui lòng nhập mã khác!');
    END IF;
  ELSE
    SELECT COUNT(*) INTO v_cnt FROM DEMO_TREATMENTS WHERE LOWER(TREATMENT_CODE) = LOWER(TRIM(:p_treatment_code)) AND TREATMENT_ID <> v_treatment_id;
    IF v_cnt > 0 THEN
      raise_application_error(-20001, 'Mã điều trị đã tồn tại ở đợt điều trị khác. Vui lòng nhập mã khác!');
    END IF;
  END IF;

  IF v_treatment_id IS NULL OR v_treatment_id = '' THEN
    SELECT TO_CHAR(DEMO_TREATMENTS_SEQ.NEXTVAL) INTO v_treatment_id FROM DUAL;
    INSERT INTO DEMO_TREATMENTS (
      TREATMENT_ID, TREATMENT_CODE, MEDICAL_RECORD_ID, PATIENT_ID,
      DOCTOR_ID, ROOM_ID, BED_NUMBER, TREATMENT_TYPE,
      DESCRIPTION, START_DATE, END_DATE, COST,
      STATUS, CREATED_BY, CREATED_DATE
    ) VALUES (
      v_treatment_id, :p_treatment_code, :p_medical_record_id, :p_patient_id,
      :p_doctor_id, :p_room_id, :p_bed_number, :p_treatment_type,
      :p_description, v_start_date, v_end_date, NVL(:p_cost, 0),
      NVL(:p_status, 'PLANNED'), NVL(:p_created_by, USER), SYSDATE
    );
  ELSE
    UPDATE DEMO_TREATMENTS
       SET TREATMENT_CODE    = :p_treatment_code,
           MEDICAL_RECORD_ID = :p_medical_record_id,
           PATIENT_ID        = :p_patient_id,
           DOCTOR_ID         = :p_doctor_id,
           ROOM_ID           = :p_room_id,
           BED_NUMBER        = :p_bed_number,
           TREATMENT_TYPE    = :p_treatment_type,
           DESCRIPTION       = :p_description,
           START_DATE        = v_start_date,
           END_DATE          = v_end_date,
           COST              = NVL(:p_cost, 0),
           STATUS            = NVL(:p_status, STATUS)
     WHERE TREATMENT_ID = v_treatment_id;
  END IF;
  :p_treatment_id_out := v_treatment_id;
END;
